select count(*) from postgres.comments as c, postgres.posts as p, postgres.postlinks as pl, postgres.posthistory as ph, postgres.votes as v, postgres.badges as b, postgres.users as u where p.id = pl.relatedpostid and b.userid = u.id and c.userid = u.id and p.id = v.postid and p.id = c.postid and p.id = ph.postid and c.creationdate>=timestamp '2010-08-01 19:11:47' and c.creationdate<=timestamp '2014-09-11 13:42:51' and p.answercount<=4 and p.favoritecount>=0 and pl.linktypeid=1 and v.votetypeid=2 and v.creationdate<=timestamp '2014-09-10 00:00:00' and b."date"<=timestamp '2014-08-02 12:24:29';
